		    if (existingInput) return existingInput;
		
		    var input = document.createElement("input");
		    input.id = id;
		    input.type = "text";
		    input.style.position = "absolute";
		    
		    var canvas = document.getElementById("canvas");
		    var rect = canvas.getBoundingClientRect();
		    
		    // Posisi tetap presisi
		    input.style.left = (rect.left + window.pageXOffset + x) + "px";
		    input.style.top = (rect.top + window.pageYOffset + y) + "px";
		    input.style.width = w + "px";
		    input.style.height = h + "px";
		    
		    // --- PENGATURAN TAMPILAN ---
		    input.style.zIndex = "10000";
		    input.style.background = "transparent"; 
		    input.style.border = "none";             
		    input.style.outline = "none";            
		    input.style.pointerEvents = "auto";
		    
		    // --- AGAR TEKS DI TENAH ---
		    input.style.textAlign = "center"; // Membuat teks berada di tengah horizontal
		    // --------------------------
		
		    input.style.fontFamily = "Verdana, sans-serif";
		    input.style.fontWeight = "bold";
		    input.style.fontSize = "18px";
		    input.style.color = "#000000"; 
		    
